#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    int *queries = (int*)malloc(T*sizeof(int));
    int maxN = 0;
    for(int i=0;i<T;i++){
        scanf("%d", &queries[i]);
        if(queries[i]>maxN) maxN = queries[i];
    }
    long long *bell = (long long*)calloc(maxN+1, sizeof(long long));
    long long *prev = (long long*)calloc(maxN+2, sizeof(long long));
    long long *cur  = (long long*)calloc(maxN+2, sizeof(long long));
    prev[0] = 1; // S(0,0)
    bell[0] = 1;
    for(int n=1;n<=maxN;n++){
        cur[0] = 0;
        for(int k=1;k<=n;k++){
            cur[k] = ( (k * prev[k]) % MOD + prev[k-1] ) % MOD; // S(n,k)
        }
        long long sum = 0;
        for(int k=1;k<=n;k++) sum = (sum + cur[k]) % MOD;
        bell[n] = sum;
        // swap rows
        long long *tmp = prev; prev = cur; cur = tmp;
    }
    for(int i=0;i<T;i++){
        printf("%lld\n", bell[queries[i]]);
    }
    free(queries); free(bell); free(prev); free(cur);
    return 0;
}

