    static final long MOD = 1_000_000_007L;
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        int[] queries = new int[T];
        int maxN = 0;
        for (int i = 0; i < T; i++) {
            queries[i] = Integer.parseInt(br.readLine().trim());
            if (queries[i] > maxN) maxN = queries[i];
        }
        long[] bell = new long[maxN + 1];
        long[] prev = new long[maxN + 2];
        long[] cur = new long[maxN + 2];
        prev[0] = 1; // S(0,0)
        bell[0] = 1;
        for (int n = 1; n <= maxN; n++) {
            cur[0] = 0;
            for (int k = 1; k <= n; k++) {
                cur[k] = ( (k * prev[k]) % MOD + prev[k - 1] ) % MOD; // S(n,k)
            }
            long sum = 0;
            for (int k = 1; k <= n; k++) sum = (sum + cur[k]) % MOD;
            bell[n] = sum;
            long[] tmp = prev; prev = cur; cur = tmp;
        }
        StringBuilder sb = new StringBuilder();
        for (int n : queries) sb.append(bell[n]).append('\n');
